sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {

    function updatePlugType(response) {
        if (response) {
            var parsedData = JSON.parse(response);
            g_form.setValue('u_plug_details', parsedData.plug_type);
        } else {
            g_form.addInfoMessage('Error in Plug data parsing');
        }
    }

    if ((newValue != '' && newValue != null)) {
        var plugDetails = new GlideAjax('AJAXUtils');
        plugDetails.addParam('sysparm_name', 'getPlugName');
        plugDetails.addParam('sysparm_sys_id', g_form.getValue('cmdb_ci'));
        plugDetails.getXMLAnswer(updatePlugType);
    } else {
        g_form.setValue('u_plug_details', '');
        g_form.setDisplay('u_plug_details', false);
    }
}
